+		Session:       "proj-b",
+		Category:      EventCategoryPane,
+		Type:          EventTypePaneOutput,
+		Actionability: ActionabilityBackground,
+		Severity:      SeverityInfo,
+		Summary:       "Event from proj-b",
+	})
+
